import React, { useState, useEffect } from "react";
import axios from "axios";
import Modal from "react-modal";

const KpiManager = () => {
  const [kpis, setKpis] = useState([]);
  const [newKpi, setNewKpi] = useState({
    kpiName: "",
    currentValue: "",
    unitOfMeasure: "",
    source: "",
    formula: "",
    bottomLimit: "",
    topLimit: "",
  });
  const [editingKpi, setEditingKpi] = useState(null);
  const [error, setError] = useState("");
  const [isModalOpen, setIsModalOpen] = useState(false);

  const openModal = () => setIsModalOpen(true);
  const closeModal = () => setIsModalOpen(false);

  useEffect(() => {
    fetchKpis();
  }, []);

  const fetchKpis = async () => {
    try {
      const response = await axios.get("http://localhost:5001/api/kpis");
      setKpis(response.data);
    } catch (error) {
      console.error("Error fetching kpis:", error);
      setError("Failed to load KPIs");
    }
  };

  const handleInputChange = (e, isEditing = false) => {
    const { name, value, type } = e.target;
    if (!name) return; // Prevents accidental state mutation errors

    const formattedValue = type === "number" ? Number(value) : value;

    if (isEditing) {
      setEditingKpi((prev) => ({ ...(prev || {}), [name]: formattedValue }));
    } else {
      setNewKpi((prev) => ({ ...(prev || {}), [name]: formattedValue }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post("http://localhost:5001/api/kpis", newKpi);
      setNewKpi({
        kpiName: "",
        currentValue: "",
        unitOfMeasure: "",
        source: "",
        formula: "",
        bottomLimit: "",
        topLimit: "",
      });
      fetchKpis();
      setError("");
      closeModal(); // Ensure modal closes after successful submission
    } catch (error) {
      console.error("Error creating KPI:", error);
      setError(error.response?.data?.message || "Failed to create KPI");
    }
  };

  const handleEdit = (kpi) => {
    setEditingKpi({ ...kpi }); // Ensure it's a fresh copy to avoid direct state mutation
  };

  const handleUpdate = async (e) => {
    e.preventDefault();
    try {
      await axios.patch(
        `http://localhost:5001/api/kpis/${editingKpi._id}`,
        editingKpi
      );
      setEditingKpi(null);
      fetchKpis();
      setError("");
    } catch (error) {
      console.error("Error updating KPI:", error);
      setError("Failed to update KPI");
    }
  };

  const handleToggleActive = async (kpi) => {
    try {
      await axios.patch(`http://localhost:5001/api/kpis/${kpi._id}`, {
        active: !kpi.active,
      });
      fetchKpis();
      setError("");
    } catch (error) {
      console.error("Error toggling KPI status:", error);
      setError("Failed to update KPI status");
    }
  };

  return (
    <div className="kpi-manager">
      <h2>Manage KPIs</h2>

      {error && <div className="error-message">{error}</div>}

      <table>
        <thead>
          <tr>
            <th>KPI ID</th>
            <th>Name</th>
            <th>Current Value</th>
            <th>Unit of Measure</th>
            <th>Source</th>
            <th>Formula</th>
            <th>Bottom Limit</th>
            <th>Top Limit</th>
            <th>Status</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {kpis.map((kpi) => (
            <tr key={kpi._id} className={!kpi.active ? "inactive" : ""}>
              <td>{kpi.kpiId}</td>
              <td>{kpi.kpiName}</td>
              <td>{kpi.currentValue}</td>
              <td>{kpi.unitOfMeasure}</td>
              <td>{kpi.source}</td>
              <td>{kpi.formula}</td>
              <td>{kpi.bottomLimit}</td>
              <td>{kpi.topLimit}</td>
              <td>
                <span
                  className={`status-badge ${
                    kpi.active ? "status-active" : "status-inactive"
                  }`}
                >
                  {kpi.active ? "Active" : "Inactive"}
                </span>
              </td>
              <td>
                <button
                  onClick={() => handleEdit(kpi)}
                  className="btn btn-edit"
                >
                  Edit
                </button>
                <button
                  onClick={() => handleToggleActive(kpi)}
                  className={`btn ${
                    kpi.active ? "btn-deactivate" : "btn-activate"
                  }`}
                >
                  {kpi.active ? "Deactivate" : "Activate"}
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      {/* Edit KPI Modal */}
      {editingKpi && (
        <Modal isOpen={!!editingKpi} onRequestClose={() => setEditingKpi(null)}>
          <h3>Edit KPI</h3>
          <form onSubmit={handleUpdate}>
            <input
              type="text"
              name="kpiName"
              value={editingKpi.kpiName}
              onChange={(e) => handleInputChange(e, true)}
              required
            />
            <input
              type="text"
              name="currentValue"
              value={editingKpi.currentValue}
              onChange={(e) => handleInputChange(e, true)}
              required
            />
            <input
              type="text"
              name="unitOfMeasure"
              value={editingKpi.unitOfMeasure}
              onChange={(e) => handleInputChange(e, true)}
              required
            />
            <input
              type="text"
              name="source"
              value={editingKpi.source}
              onChange={(e) => handleInputChange(e, true)}
              required
            />
            <input
              type="text"
              name="formula"
              value={editingKpi.formula}
              onChange={(e) => handleInputChange(e, true)}
              required
            />
            <input
              type="number"
              name="bottomLimit"
              value={editingKpi.bottomLimit}
              onChange={(e) => handleInputChange(e, true)}
              required
            />
            <input
              type="number"
              name="topLimit"
              value={editingKpi.topLimit}
              onChange={(e) => handleInputChange(e, true)}
              required
            />
            <button type="submit">Save Changes</button>
            <button type="button" onClick={() => setEditingKpi(null)}>
              Cancel
            </button>
          </form>
        </Modal>
      )}

      <button onClick={openModal} className="btn">
        Add New KPI
      </button>

      {/* Add KPI Modal */}
      <Modal isOpen={isModalOpen} onRequestClose={closeModal}>
        <h2>Add New KPI</h2>
        <form onSubmit={handleSubmit}>
          {Object.keys(newKpi).map((key) => (
            <input
              key={key}
              type="text"
              name={key}
              value={newKpi[key]}
              onChange={(e) => handleInputChange(e, false)}
              required
            />
          ))}
          <button type="submit">Add KPI</button>
        </form>
      </Modal>
    </div>
  );
};

export default KpiManager;
